if (! function_exists('ssl_cert_check')) {
    function ssl_cert_check($host, $port = null, $timeout = null)
    {
            $host = $host ?? '';
            $port = $port ?? 443;
            $timeout = $timeout ?? 15;

            $timeout = max(5, min(30, (int)$timeout));
            $port = max(1, min(65535, (int)$port));

            if (empty(trim($host))) {
                return ['success' => false, 'error' => 'Hostname is required.'];
            }

            // Strip protocol and path
            $host = preg_replace('#^https?://#', '', $host);
            $host = preg_replace('#/.*$#', '', $host);
            $host = preg_replace('#:\d+$#', '', $host);

            // Connect over SSL and capture the peer certificate
            $context = stream_context_create([
                'ssl' => [
                    'capture_peer_cert' => true,
                    'capture_peer_cert_chain' => true,
                    'verify_peer' => false,
                    'verify_peer_name' => false,
                    'allow_self_signed' => true,
                ]
