            $target = "ssl://{$host}:{$port}";
            $errno = 0;
            $errstr = '';
            $start_time = microtime(true);
            $stream = @stream_socket_client($target, $errno, $errstr, $timeout, STREAM_CLIENT_CONNECT, $context);
            $connect_time_ms = round((microtime(true) - $start_time) * 1000, 1);

            if (!$stream) {
                return [
                    'success' => false,
                    'error' => "SSL connection failed: $errstr ($errno)",
                    'host' => $host,
                    'port' => $port,
                ];
            }

            // Get the certificate
            $options = stream_context_get_options($context);
            $cert = $options['ssl']['peer_certificate'] ?? null;
            $cert_chain = $options['ssl']['peer_certificate_chain'] ?? [];

            if (!$cert) {
                fclose($stream);
                return [
                    'success' => false,
                    'error' => 'No peer certificate captured. Server may not have presented one.',
                    'host' => $host,
                    'port' => $port,
                ];
            }

            // Parse the certificate
            $cert_data = @openssl_x509_parse($cert, true);
            if (!$cert_data) {
                fclose($stream);
                return [
                    'success' => false,
                    'error' => 'Failed to parse certificate data.',
                    'host' => $host,
                    'port' => $port,
                ];
            }

            // Also try to get the certificate in PEM format for export
            $cert_pem = '';
            @openssl_x509_export($cert, $cert_pem);

            // Parse chain certificates
            $chain_data = [];
            foreach ($cert_chain as $i => $chain_cert) {
                $parsed = @openssl_x509_parse($chain_cert, true);
                if ($parsed) {
                    $chain_data[] = [
                        'index' => $i + 1,
                        'subject' => $parsed['subject'] ?? [],
                        'issuer' => $parsed['issuer'] ?? [],
                        'valid_from' => $parsed['validFrom_time_t'] ?? null,
                        'valid_to' => $parsed['validTo_time_t'] ?? null,
