            // Extract key fields from certificate data
            $subject = $cert_data['subject'] ?? [];
            $issuer = $cert_data['issuer'] ?? [];

            // Validity dates (openssl_x509_parse gives timestamps)
            $valid_from_ts = $cert_data['validFrom_time_t'] ?? null;
            $valid_to_ts = $cert_data['validTo_time_t'] ?? null;
            $now_ts = time();

            $days_remaining = null;
            $expired = false;
            $not_yet_valid = false;

            if ($valid_to_ts) {
                $days_remaining = (int)ceil(($valid_to_ts - $now_ts) / 86400);
                $expired = $now_ts > $valid_to_ts;
            }
            if ($valid_from_ts) {
                $not_yet_valid = $now_ts < $valid_from_ts;
            }

            // Subject Alternative Names (SANs) from extensions
            $sans = [];
            $extensions = $cert_data['extensions'] ?? [];
            if (isset($extensions['subjectAltName'])) {
                $san_str = $extensions['subjectAltName'];
                // Parse SANs: "DNS:example.com, DNS:www.example.com, DNS:*.example.com"
                $parts = explode(',', $san_str);
                foreach ($parts as $part) {
                    $part = trim($part);
                    if (preg_match('/^DNS:(.+)$/i', $part, $m)) {
                        $sans[] = $m[1];
                    } elseif (preg_match('/^IP Address:(.+)$/i', $part, $m)) {
                        $sans[] = 'IP:' . $m[1];
                    }
                }
            }

            // CN from subject
            $common_name = $subject['CN'] ?? '';

            // Check if wildcard
            $is_wildcard = strpos($common_name, '*') === 0;
            foreach ($sans as $san) {
                if (strpos($san, '*') === 0) {
                    $is_wildcard = true;
                    break;
                }
            }

            // Signature algorithm
            $sig_algo = $cert_data['signatureTypeSN'] ?? $cert_data['signatureTypeLN'] ?? '';

            // Serial number
            $serial = $cert_data['serialNumber'] ?? '';
            $serial_hex = $serial;
            // Try to convert to hex if it's a decimal
            if (is_numeric($serial) && $serial > 0) {
                $serial_hex = '0x' . dechex((int)$serial);
            }

            // Key size (RSA/DSA/EC key size)
            $key_size = null;

